import{_ as n,c as t,o as a,a1 as r}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Plan-Review: KI-Pläne visuell überprüfen | Plannotator","description":"Lernen Sie die Plan-Review-Funktion von Plannotator. Nutzen Sie die visuelle Oberfläche zur Überprüfung von KI-generierten Plänen, fügen Sie Anmerkungen hinzu, genehmigen oder lehnen Sie ab. Verstehen Sie den Unterschied zwischen Approve und Request Changes.","frontmatter":{"title":"Plan-Review: KI-Pläne visuell überprüfen | Plannotator","subtitle":"Grundlagen des Plan-Reviews: KI-Pläne visuell überprüfen","description":"Lernen Sie die Plan-Review-Funktion von Plannotator. Nutzen Sie die visuelle Oberfläche zur Überprüfung von KI-generierten Plänen, fügen Sie Anmerkungen hinzu, genehmigen oder lehnen Sie ab. Verstehen Sie den Unterschied zwischen Approve und Request Changes.","sidebarTitle":"Plan-Review in 5 Minuten","tags":["Plan-Review","Visuelle Überprüfung","Anmerkungen","Genehmigung","Ablehnung","Claude Code","OpenCode"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"de/backnotprop/plannotator/platforms/plan-review-basics/index.md","filePath":"de/backnotprop/plannotator/platforms/plan-review-basics/index.md"}'),i={name:"de/backnotprop/plannotator/platforms/plan-review-basics/index.md"};function s(l,e,o,d,u,p){return a(),t("div",null,[...e[0]||(e[0]=[r(`<h1 id="grundlagen-des-plan-reviews-ki-plane-visuell-uberprufen" tabindex="-1">Grundlagen des Plan-Reviews: KI-Pläne visuell überprüfen <a class="header-anchor" href="#grundlagen-des-plan-reviews-ki-plane-visuell-uberprufen" aria-label="Permalink to &quot;Grundlagen des Plan-Reviews: KI-Pläne visuell überprüfen&quot;">​</a></h1><h2 id="was-sie-lernen-werden" tabindex="-1">Was Sie lernen werden <a class="header-anchor" href="#was-sie-lernen-werden" aria-label="Permalink to &quot;Was Sie lernen werden&quot;">​</a></h2><ul><li>✅ KI-generierte Pläne mit der visuellen Oberfläche von Plannotator überprüfen</li><li>✅ Plantext markieren und verschiedene Anmerkungstypen hinzufügen (Löschen, Ersetzen, Kommentieren)</li><li>✅ Pläne genehmigen, damit die KI mit der Umsetzung fortfahren kann</li><li>✅ Pläne ablehnen und Anmerkungen als Feedback an die KI senden</li><li>✅ Anwendungsfälle und Unterschiede der Anmerkungstypen verstehen</li></ul><h2 id="ihre-aktuelle-herausforderung" tabindex="-1">Ihre aktuelle Herausforderung <a class="header-anchor" href="#ihre-aktuelle-herausforderung" aria-label="Permalink to &quot;Ihre aktuelle Herausforderung&quot;">​</a></h2><p><strong>Problem 1</strong>: KI-generierte Umsetzungspläne im Terminal zu lesen ist mühsam – viel Text, unklare Struktur, anstrengende Überprüfung.</p><p><strong>Problem 2</strong>: Feedback an die KI zu geben erfordert umständliche Textbeschreibungen wie „lösche Absatz 3&quot; oder „ändere diese Funktion&quot;. Hoher Kommunikationsaufwand, und die KI kann es falsch verstehen.</p><p><strong>Problem 3</strong>: Manche Stellen im Plan brauchen keine Änderung, andere müssen ersetzt werden, wieder andere brauchen einen Kommentar – aber es fehlt ein Tool, um dieses Feedback zu strukturieren.</p><p><strong>Problem 4</strong>: Unklar, wie Sie der KI mitteilen, ob Sie den Plan genehmigt haben oder Änderungen wünschen.</p><p><strong>Plannotator hilft Ihnen dabei</strong>:</p><ul><li>Visuelle Oberfläche statt Terminal-Lesen, klare Struktur</li><li>Text markieren und Anmerkungen hinzufügen (Löschen, Ersetzen, Kommentieren), präzises Feedback</li><li>Anmerkungen werden automatisch in strukturierte Daten umgewandelt, die KI versteht Ihre Absicht genau</li><li>Ein Klick zum Genehmigen oder Ablehnen, sofortige KI-Reaktion</li></ul><h2 id="wann-sie-diese-funktion-nutzen" tabindex="-1">Wann Sie diese Funktion nutzen <a class="header-anchor" href="#wann-sie-diese-funktion-nutzen" aria-label="Permalink to &quot;Wann Sie diese Funktion nutzen&quot;">​</a></h2><p><strong>Anwendungsfälle</strong>:</p><ul><li>KI-Agent hat den Plan fertiggestellt und ruft <code>ExitPlanMode</code> auf (Claude Code)</li><li>KI-Agent ruft das <code>submit_plan</code>-Tool auf (OpenCode)</li><li>Sie müssen einen KI-generierten Umsetzungsplan überprüfen</li><li>Sie möchten präzises Feedback zu Planänderungen geben</li></ul><p><strong>Nicht geeignet für</strong>:</p><ul><li>Direkte Code-Umsetzung durch die KI (Plan-Review überspringen)</li><li>Plan bereits genehmigt, tatsächliche Code-Änderungen überprüfen (nutzen Sie die Code-Review-Funktion)</li></ul><h2 id="🎒-vorbereitung" tabindex="-1">🎒 Vorbereitung <a class="header-anchor" href="#🎒-vorbereitung" aria-label="Permalink to &quot;🎒 Vorbereitung&quot;">​</a></h2><p><strong>Voraussetzungen</strong>:</p><ul><li>✅ Plannotator CLI installiert (siehe <a href="./../start/getting-started/">Schnellstart</a>)</li><li>✅ Claude Code oder OpenCode Plugin konfiguriert (siehe entsprechende Installationsanleitung)</li><li>✅ KI-Agent unterstützt Plan-Review (Claude Code 2.1.7+ oder OpenCode)</li></ul><p><strong>Auslöser</strong>:</p><ul><li><strong>Claude Code</strong>: Nach Abschluss des Plans ruft die KI automatisch <code>ExitPlanMode</code> auf, Plannotator startet automatisch</li><li><strong>OpenCode</strong>: KI ruft das <code>submit_plan</code>-Tool auf, Plannotator startet automatisch</li></ul><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><h3 id="was-ist-plan-review" tabindex="-1">Was ist Plan-Review <a class="header-anchor" href="#was-ist-plan-review" aria-label="Permalink to &quot;Was ist Plan-Review&quot;">​</a></h3><p><strong>Plan-Review</strong> ist die Kernfunktion von Plannotator zur visuellen Überprüfung von KI-generierten Umsetzungsplänen.</p><div class="info custom-block"><p class="custom-block-title">Warum brauchen Sie Plan-Review?</p><p>Nachdem die KI einen Plan erstellt hat, fragt sie normalerweise „Ist dieser Plan in Ordnung?&quot; oder „Soll ich mit der Umsetzung beginnen?&quot;. Ohne visuelles Tool können Sie nur reinen Text im Terminal lesen und dann vage antworten wie „OK&quot; oder „Nein, ändere XX&quot;. Mit Plannotator können Sie den Plan in einer visuellen Oberfläche betrachten, genau die zu ändernden Stellen markieren und strukturierte Anmerkungen hinzufügen – die KI versteht Ihre Absicht besser.</p></div><h3 id="arbeitsablauf" tabindex="-1">Arbeitsablauf <a class="header-anchor" href="#arbeitsablauf" aria-label="Permalink to &quot;Arbeitsablauf&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  KI-Agent       │</span></span>
<span class="line"><span>│  (erstellt Plan)│</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         │ ExitPlanMode / submit_plan</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│ Plannotator UI  │  ← Browser öffnet automatisch</span></span>
<span class="line"><span>│                 │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ Planinhalt │  │</span></span>
<span class="line"><span>│ │ (Markdown) │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>│       │         │</span></span>
<span class="line"><span>│       │ Text markieren</span></span>
<span class="line"><span>│       ▼         │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ Anmerkung  │  │</span></span>
<span class="line"><span>│ │ hinzufügen │  │</span></span>
<span class="line"><span>│ │ Delete/    │  │</span></span>
<span class="line"><span>│ │ Replace/   │  │</span></span>
<span class="line"><span>│ │ Comment    │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>│       │         │</span></span>
<span class="line"><span>│       ▼         │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ Entscheidung│ │</span></span>
<span class="line"><span>│ │ Approve/  │  │</span></span>
<span class="line"><span>│ │ Request   │  │</span></span>
<span class="line"><span>│ │ Changes   │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         │ {&quot;behavior&quot;: &quot;allow&quot;} oder</span></span>
<span class="line"><span>         │ {&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  KI-Agent       │</span></span>
<span class="line"><span>│  (setzt um)     │</span></span>
<span class="line"><span>└─────────────────┘</span></span></code></pre></div><h3 id="anmerkungstypen" tabindex="-1">Anmerkungstypen <a class="header-anchor" href="#anmerkungstypen" aria-label="Permalink to &quot;Anmerkungstypen&quot;">​</a></h3><p>Plannotator unterstützt vier Anmerkungstypen, jeder mit unterschiedlichem Zweck:</p><table tabindex="0"><thead><tr><th>Anmerkungstyp</th><th>Zweck</th><th>Feedback an die KI</th></tr></thead><tbody><tr><td><strong>Delete</strong></td><td>Unerwünschten Inhalt löschen</td><td>„Löschen: [markierter Text]&quot;</td></tr><tr><td><strong>Replace</strong></td><td>Durch besseren Inhalt ersetzen</td><td>„Ersetzen: [markierter Text] durch [Ihr eingegebener Text]&quot;</td></tr><tr><td><strong>Comment</strong></td><td>Einen Abschnitt kommentieren, keine Änderung erforderlich</td><td>„Kommentar: [markierter Text]. Hinweis: [Ihr Kommentar]&quot;</td></tr><tr><td><strong>Global Comment</strong></td><td>Globaler Kommentar, nicht an bestimmten Text gebunden</td><td>„Globaler Kommentar: [Ihr Kommentar]&quot;</td></tr></tbody></table><h3 id="approve-vs-request-changes" tabindex="-1">Approve vs Request Changes <a class="header-anchor" href="#approve-vs-request-changes" aria-label="Permalink to &quot;Approve vs Request Changes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Entscheidungstyp</th><th>Aktion</th><th>Feedback an die KI</th><th>Anwendungsfall</th></tr></thead><tbody><tr><td><strong>Approve</strong></td><td>Approve-Button klicken</td><td><code>{&quot;behavior&quot;: &quot;allow&quot;}</code></td><td>Plan ist in Ordnung, direkt genehmigen</td></tr><tr><td><strong>Request Changes</strong></td><td>Request Changes-Button klicken</td><td><code>{&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</code></td><td>Änderungen erforderlich</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Unterschiede zwischen Claude Code und OpenCode</p><ul><li><strong>Claude Code</strong>: Bei Approve werden Anmerkungen nicht gesendet (werden ignoriert)</li><li><strong>OpenCode</strong>: Bei Approve können Anmerkungen optional als Notizen gesendet werden</li></ul><p><strong>Bei Planablehnung</strong>: Auf beiden Plattformen werden Anmerkungen an die KI gesendet</p></div><h2 id="schritt-fur-schritt-anleitung" tabindex="-1">Schritt-für-Schritt-Anleitung <a class="header-anchor" href="#schritt-fur-schritt-anleitung" aria-label="Permalink to &quot;Schritt-für-Schritt-Anleitung&quot;">​</a></h2><h3 id="schritt-1-plan-review-auslosen" tabindex="-1">Schritt 1: Plan-Review auslösen <a class="header-anchor" href="#schritt-1-plan-review-auslosen" aria-label="Permalink to &quot;Schritt 1: Plan-Review auslösen&quot;">​</a></h3><p><strong>Claude Code Beispiel</strong>:</p><p>Führen Sie in Claude Code ein Gespräch mit der KI, um einen Umsetzungsplan zu erstellen:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Benutzer: Erstelle mir einen Umsetzungsplan für ein Benutzerauthentifizierungsmodul</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Claude: Hier ist der Umsetzungsplan:</span></span>
<span class="line"><span>1. Benutzermodell erstellen</span></span>
<span class="line"><span>2. Registrierungs-API implementieren</span></span>
<span class="line"><span>3. Login-API implementieren</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>(KI ruft ExitPlanMode auf)</span></span></code></pre></div><p><strong>OpenCode Beispiel</strong>:</p><p>In OpenCode ruft die KI automatisch das <code>submit_plan</code>-Tool auf.</p><p><strong>Was Sie sehen sollten</strong>:</p><ol><li>Browser öffnet automatisch die Plannotator-Oberfläche</li><li>Der KI-generierte Planinhalt wird angezeigt (Markdown-Format)</li><li>Am unteren Seitenrand befinden sich die Buttons „Approve&quot; und „Request Changes&quot;</li></ol><h3 id="schritt-2-planinhalt-durchsehen" tabindex="-1">Schritt 2: Planinhalt durchsehen <a class="header-anchor" href="#schritt-2-planinhalt-durchsehen" aria-label="Permalink to &quot;Schritt 2: Planinhalt durchsehen&quot;">​</a></h3><p>Betrachten Sie den Plan im Browser:</p><ul><li>Der Plan wird im Markdown-Format gerendert, einschließlich Überschriften, Absätze, Listen, Codeblöcke</li><li>Sie können durch den gesamten Plan scrollen</li><li>Hell-/Dunkelmodus-Umschaltung wird unterstützt (Theme-Umschalter oben rechts)</li></ul><h3 id="schritt-3-plantext-markieren-und-anmerkungen-hinzufugen" tabindex="-1">Schritt 3: Plantext markieren und Anmerkungen hinzufügen <a class="header-anchor" href="#schritt-3-plantext-markieren-und-anmerkungen-hinzufugen" aria-label="Permalink to &quot;Schritt 3: Plantext markieren und Anmerkungen hinzufügen&quot;">​</a></h3><p><strong>Delete-Anmerkung hinzufügen</strong>:</p><ol><li>Markieren Sie mit der Maus den zu löschenden Text im Plan</li><li>Klicken Sie in der erscheinenden Werkzeugleiste auf <strong>Delete</strong></li><li>Der Text wird als gelöscht markiert (rote Durchstreichung)</li></ol><p><strong>Replace-Anmerkung hinzufügen</strong>:</p><ol><li>Markieren Sie mit der Maus den zu ersetzenden Text im Plan</li><li>Klicken Sie in der erscheinenden Werkzeugleiste auf <strong>Replace</strong></li><li>Geben Sie im erscheinenden Eingabefeld den Ersatztext ein</li><li>Drücken Sie Enter oder klicken Sie auf Bestätigen</li><li>Der Originaltext wird als ersetzt markiert (gelber Hintergrund), der Ersatztext erscheint darunter</li></ol><p><strong>Comment-Anmerkung hinzufügen</strong>:</p><ol><li>Markieren Sie mit der Maus den zu kommentierenden Text im Plan</li><li>Klicken Sie in der erscheinenden Werkzeugleiste auf <strong>Comment</strong></li><li>Geben Sie im erscheinenden Eingabefeld Ihren Kommentar ein</li><li>Drücken Sie Enter oder klicken Sie auf Bestätigen</li><li>Der Text wird als kommentiert markiert (blaue Hervorhebung), der Kommentar erscheint in der Seitenleiste</li></ol><p><strong>Global Comment hinzufügen</strong>:</p><ol><li>Klicken Sie oben rechts auf <strong>Add Global Comment</strong></li><li>Geben Sie im erscheinenden Eingabefeld Ihren globalen Kommentar ein</li><li>Drücken Sie Enter oder klicken Sie auf Bestätigen</li><li>Der Kommentar erscheint im Bereich „Global Comments&quot; der Seitenleiste</li></ol><p><strong>Was Sie sehen sollten</strong>:</p><ul><li>Nach dem Markieren von Text erscheint sofort eine Werkzeugleiste (Delete, Replace, Comment)</li><li>Nach dem Hinzufügen von Anmerkungen zeigt der Text den entsprechenden Stil (Durchstreichung, Hintergrundfarbe, Hervorhebung)</li><li>Die Seitenleiste zeigt alle Anmerkungen, Klick springt zur entsprechenden Position</li><li>Sie können auf <strong>Löschen</strong> neben einer Anmerkung klicken, um sie zu entfernen</li></ul><h3 id="schritt-4-plan-genehmigen" tabindex="-1">Schritt 4: Plan genehmigen <a class="header-anchor" href="#schritt-4-plan-genehmigen" aria-label="Permalink to &quot;Schritt 4: Plan genehmigen&quot;">​</a></h3><p><strong>Wenn der Plan in Ordnung ist</strong>:</p><p>Klicken Sie auf den <strong>Approve</strong>-Button am unteren Seitenrand.</p><p><strong>Was Sie sehen sollten</strong>:</p><ul><li>Browser schließt automatisch (1,5 Sekunden Verzögerung)</li><li>Claude Code/OpenCode Terminal zeigt, dass der Plan genehmigt wurde</li><li>KI fährt mit der Umsetzung fort</li></ul><div class="info custom-block"><p class="custom-block-title">Verhalten von Approve</p><ul><li><strong>Claude Code</strong>: Sendet nur <code>{&quot;behavior&quot;: &quot;allow&quot;}</code>, Anmerkungen werden ignoriert</li><li><strong>OpenCode</strong>: Sendet <code>{&quot;behavior&quot;: &quot;allow&quot;}</code>, Anmerkungen können optional als Notizen gesendet werden</li></ul></div><h3 id="schritt-5-plan-ablehnen-request-changes" tabindex="-1">Schritt 5: Plan ablehnen (Request Changes) <a class="header-anchor" href="#schritt-5-plan-ablehnen-request-changes" aria-label="Permalink to &quot;Schritt 5: Plan ablehnen (Request Changes)&quot;">​</a></h3><p><strong>Wenn der Plan Änderungen benötigt</strong>:</p><ol><li>Fügen Sie die notwendigen Anmerkungen hinzu (Delete, Replace, Comment)</li><li>Klicken Sie auf den <strong>Request Changes</strong>-Button am unteren Seitenrand</li><li>Ein Bestätigungsdialog erscheint</li></ol><p><strong>Was Sie sehen sollten</strong>:</p><ul><li>Bestätigungsdialog zeigt „Send X annotations to AI?&quot;</li><li>Nach Bestätigung schließt der Browser automatisch</li><li>Claude Code/OpenCode Terminal zeigt den Feedback-Inhalt</li><li>KI wird den Plan basierend auf dem Feedback überarbeiten</li></ul><div class="tip custom-block"><p class="custom-block-title">Verhalten von Request Changes</p><ul><li><strong>Claude Code</strong> und <strong>OpenCode</strong>: Beide senden <code>{&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</code></li><li>Anmerkungen werden in strukturierten Markdown-Text umgewandelt</li><li>KI überarbeitet den Plan und ruft erneut ExitPlanMode/submit_plan auf</li></ul></div><h3 id="schritt-6-feedback-inhalt-anzeigen-optional" tabindex="-1">Schritt 6: Feedback-Inhalt anzeigen (optional) <a class="header-anchor" href="#schritt-6-feedback-inhalt-anzeigen-optional" aria-label="Permalink to &quot;Schritt 6: Feedback-Inhalt anzeigen (optional)&quot;">​</a></h3><p>Wenn Sie den von Plannotator an die KI gesendeten Feedback-Inhalt sehen möchten, schauen Sie im Terminal:</p><p><strong>Claude Code</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Plan rejected by user</span></span>
<span class="line"><span>Please modify the plan based on the following feedback:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[Strukturierter Anmerkungsinhalt]</span></span></code></pre></div><p><strong>OpenCode</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;feedback&gt;</span></span>
<span class="line"><span>[Strukturierter Anmerkungsinhalt]</span></span>
<span class="line"><span>&lt;/feedback&gt;</span></span></code></pre></div><h2 id="checkliste-✅" tabindex="-1">Checkliste ✅ <a class="header-anchor" href="#checkliste-✅" aria-label="Permalink to &quot;Checkliste ✅&quot;">​</a></h2><p>Nach Abschluss der obigen Schritte sollten Sie in der Lage sein:</p><ul><li>[ ] Nach Auslösung des Plan-Reviews durch die KI öffnet der Browser automatisch die Plannotator-Oberfläche</li><li>[ ] Plantext markieren und Delete-, Replace-, Comment-Anmerkungen hinzufügen</li><li>[ ] Global Comment hinzufügen</li><li>[ ] Alle Anmerkungen in der Seitenleiste anzeigen und zur entsprechenden Position springen</li><li>[ ] Approve klicken, Browser schließt, KI setzt um</li><li>[ ] Request Changes klicken, Browser schließt, KI überarbeitet den Plan</li></ul><p><strong>Bei Problemen</strong> siehe:</p><ul><li><a href="./../../faq/common-problems/">Häufige Probleme</a></li><li><a href="./../../start/installation-claude-code/">Claude Code Installationsanleitung</a></li><li><a href="./../../start/installation-opencode/">OpenCode Installationsanleitung</a></li></ul><h2 id="haufige-fehler" tabindex="-1">Häufige Fehler <a class="header-anchor" href="#haufige-fehler" aria-label="Permalink to &quot;Häufige Fehler&quot;">​</a></h2><p><strong>Häufiger Fehler 1</strong>: Nach dem Markieren von Text erscheint keine Werkzeugleiste</p><p><strong>Ursache</strong>: Möglicherweise wurde Text in einem Codeblock markiert, oder der markierte Text erstreckt sich über mehrere Elemente.</p><p><strong>Lösung</strong>:</p><ul><li>Versuchen Sie, Text innerhalb eines einzelnen Absatzes oder Listenelements zu markieren</li><li>Für Codeblöcke verwenden Sie Comment-Anmerkungen, markieren Sie nicht über mehrere Zeilen</li></ul><p><strong>Häufiger Fehler 2</strong>: Nach dem Hinzufügen einer Replace-Anmerkung wird der Ersatztext nicht angezeigt</p><p><strong>Ursache</strong>: Das Eingabefeld für den Ersatztext wurde möglicherweise nicht korrekt abgeschickt.</p><p><strong>Lösung</strong>:</p><ul><li>Nach Eingabe des Ersatztextes Enter drücken oder auf Bestätigen klicken</li><li>Prüfen Sie, ob der Ersatztext in der Seitenleiste angezeigt wird</li></ul><p><strong>Häufiger Fehler 3</strong>: Nach Klick auf Approve oder Request Changes schließt der Browser nicht</p><p><strong>Ursache</strong>: Möglicherweise ein Serverfehler oder Netzwerkproblem.</p><p><strong>Lösung</strong>:</p><ul><li>Prüfen Sie das Terminal auf Fehlermeldungen</li><li>Schließen Sie den Browser manuell</li><li>Bei anhaltenden Problemen siehe <a href="./../../faq/troubleshooting/">Fehlerbehebung</a></li></ul><p><strong>Häufiger Fehler 4</strong>: KI ändert nach Erhalt des Feedbacks nicht gemäß den Anmerkungen</p><p><strong>Ursache</strong>: Die KI hat möglicherweise die Absicht der Anmerkungen nicht richtig verstanden.</p><p><strong>Lösung</strong>:</p><ul><li>Versuchen Sie, eindeutigere Anmerkungen zu verwenden (Replace ist eindeutiger als Comment)</li><li>Verwenden Sie Comment für detaillierte Erklärungen</li><li>Bei anhaltenden Problemen können Sie den Plan erneut ablehnen und die Anmerkungen anpassen</li></ul><p><strong>Häufiger Fehler 5</strong>: Nach mehreren Delete-Anmerkungen löscht die KI nur einen Teil des Inhalts</p><p><strong>Ursache</strong>: Mehrere Delete-Anmerkungen überlappen oder kollidieren möglicherweise.</p><p><strong>Lösung</strong>:</p><ul><li>Stellen Sie sicher, dass sich die Textbereiche der Delete-Anmerkungen nicht überlappen</li><li>Wenn Sie einen großen Abschnitt löschen möchten, markieren Sie den gesamten Absatz auf einmal</li></ul><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><p>Plan-Review ist die Kernfunktion von Plannotator, mit der Sie KI-generierte Pläne visuell überprüfen können:</p><p><strong>Kernoperationen</strong>:</p><ol><li><strong>Auslösen</strong>: KI ruft <code>ExitPlanMode</code> oder <code>submit_plan</code> auf, Browser öffnet automatisch die Oberfläche</li><li><strong>Durchsehen</strong>: Planinhalt in der visuellen Oberfläche betrachten (Markdown-Format)</li><li><strong>Anmerken</strong>: Text markieren, Delete, Replace, Comment oder Global Comment hinzufügen</li><li><strong>Entscheiden</strong>: Approve (genehmigen) oder Request Changes (ablehnen) klicken</li><li><strong>Feedback</strong>: Anmerkungen werden in strukturierte Daten umgewandelt, KI fährt fort oder überarbeitet den Plan</li></ol><p><strong>Anmerkungstypen</strong>:</p><ul><li><strong>Delete</strong>: Unerwünschten Inhalt löschen</li><li><strong>Replace</strong>: Durch besseren Inhalt ersetzen</li><li><strong>Comment</strong>: Einen Abschnitt kommentieren, keine Änderung erforderlich</li><li><strong>Global Comment</strong>: Globaler Kommentar, nicht an bestimmten Text gebunden</li></ul><p><strong>Entscheidungstypen</strong>:</p><ul><li><strong>Approve</strong>: Plan ist in Ordnung, direkt genehmigen (Claude Code ignoriert Anmerkungen)</li><li><strong>Request Changes</strong>: Änderungen erforderlich, Anmerkungen werden an die KI gesendet</li></ul><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen Sie <strong><a href="./../plan-review-annotations/">Plan-Anmerkungen hinzufügen</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Wie Sie Delete, Replace, Comment-Anmerkungen präzise verwenden</li><li>Wie Sie Bildanmerkungen hinzufügen</li><li>Wie Sie Anmerkungen bearbeiten und löschen</li><li>Best Practices und häufige Szenarien für Anmerkungen</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie hier, um die Quellcode-Positionen anzuzeigen</strong></summary><blockquote><p>Aktualisiert: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilen</th></tr></thead><tbody><tr><td>Plan-Review UI</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>1-200</td></tr><tr><td>Anmerkungstyp-Definition</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/types.ts#L1-L70" target="_blank" rel="noreferrer"><code>packages/ui/types.ts</code></a></td><td>1-70</td></tr><tr><td>Plan-Review-Server</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L91-L310" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>91-310</td></tr><tr><td>API: Planinhalt abrufen</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L132-L134" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>132-134</td></tr><tr><td>API: Plan genehmigen</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L201-L277" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>201-277</td></tr><tr><td>API: Plan ablehnen</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L280-L309" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>280-309</td></tr><tr><td>Viewer-Komponente</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Viewer.tsx#L1-L100" target="_blank" rel="noreferrer"><code>packages/ui/components/Viewer.tsx</code></a></td><td>1-100</td></tr><tr><td>AnnotationPanel-Komponente</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/AnnotationPanel.tsx#L1-L50" target="_blank" rel="noreferrer"><code>packages/ui/components/AnnotationPanel.tsx</code></a></td><td>1-50</td></tr></tbody></table><p><strong>Wichtige Typen</strong>:</p><ul><li><code>AnnotationType</code>: Anmerkungstyp-Enum (DELETION, INSERTION, REPLACEMENT, COMMENT, GLOBAL_COMMENT) (<code>packages/ui/types.ts:1-7</code>)</li><li><code>Annotation</code>: Anmerkungsschnittstelle (<code>packages/ui/types.ts:11-33</code>)</li><li><code>Block</code>: Planblock-Schnittstelle (<code>packages/ui/types.ts:35-44</code>)</li></ul><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>startPlannotatorServer()</code>: Startet den Plan-Review-Server (<code>packages/server/index.ts:91</code>)</li><li><code>parseMarkdownToBlocks()</code>: Parst Markdown in Blocks (<code>packages/ui/utils/parser.ts</code>)</li></ul><p><strong>API-Routen</strong>:</p><ul><li><code>GET /api/plan</code>: Planinhalt abrufen (<code>packages/server/index.ts:132</code>)</li><li><code>POST /api/approve</code>: Plan genehmigen (<code>packages/server/index.ts:201</code>)</li><li><code>POST /api/deny</code>: Plan ablehnen (<code>packages/server/index.ts:280</code>)</li></ul><p><strong>Geschäftsregeln</strong>:</p><ul><li>Claude Code sendet bei Genehmigung keine Anmerkungen (<code>apps/hook/server/index.ts:132</code>)</li><li>OpenCode kann bei Genehmigung Anmerkungen als Notizen senden (<code>apps/opencode-plugin/index.ts:270</code>)</li><li>Bei Planablehnung werden Anmerkungen immer gesendet (<code>apps/hook/server/index.ts:154</code>)</li></ul></details>`,112)])])}const g=n(i,[["render",s]]);export{h as __pageData,g as default};
